parameters.text:
=Analyze the following technical article and return a JSON object with these exact fields:

- "title": string - The article title (clean up if needed, keep original language)
- "author": string - The author name (use the provided author if available, otherwise deduce from content, or use "Unknown")
- "description": string - A concise SEO meta description in English (max 160 chars). Describe what the reader will learn or what the article covers. Do NOT include or rephrase the article title — the title is already displayed separately.
- "tags": string[] - 2 to 5 specific technical tags in lowercase. Use precise terms: library/framework names (e.g. "react", "next", "vite"), specific concepts (e.g. "server-components", "rag", "mcp"), or tool names (e.g. "cursor", "eslint"). Avoid broad/vague tags like "software-development", "programming", "web", "automation", "best-practices". Prefer 2 precise tags over 5 generic ones.
- "rating": integer - Relevance and quality score from 1 to 5 for a web developer audience (1=off-topic or low quality, 2=tangential, 3=useful, 4=very relevant and well-written, 5=must-read reference article)
- "summary": string - A detailed summary in English covering ALL key points. Use markdown formatting (headings, lists, code blocks where relevant). Do NOT start with a top-level heading repeating the title.

Article URL: {{ $json.body.url }}
Article Title: {{ $json.body.title }}
Article Author: {{ $json.body.author ?? 'Not detected' }}

Article Content:
{{ $json.body.content }}

parameters.jsCode:
const llmOutput = $input.first().json.text;

let parsed;
try {
  let jsonStr = llmOutput.trim();
  // Remove potential markdown code fences
  if (jsonStr.startsWith('```')) {
    jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Failed to parse LLM response as JSON: ${e.message}`);
}

// Validate required fields
const required = ['title', 'description', 'tags', 'rating', 'summary'];
for (const field of required) {
  if (parsed[field] === undefined || parsed[field] === null) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Type validation
if (typeof parsed.title !== 'string' || !parsed.title.length) {
  throw new Error('title must be a non-empty string');
}
if (typeof parsed.description !== 'string' || !parsed.description.length) {
  throw new Error('description must be a non-empty string');
}
if (!Array.isArray(parsed.tags) || !parsed.tags.length) {
  throw new Error('tags must be a non-empty array');
}
if (!Number.isInteger(parsed.rating) || parsed.rating < 1 || parsed.rating > 5) {
  throw new Error('rating must be an integer between 1 and 5');
}
if (typeof parsed.summary !== 'string' || !parsed.summary.length) {
  throw new Error('summary must be a non-empty string');
}

// Get original webhook data
const webhookData = $('Webhook').first().json.body;

return [{
  json: {
    ...parsed,
    url: webhookData.url,
    originalAuthor: webhookData.author,
  }
}];

const data = $input.first().json;

// Generate slug from title
const slug = data.title
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .substring(0, 80);

// Current datetime in ISO format
const pubDatetime = new Date().toISOString();

// Author
const author = data.author || data.originalAuthor || 'Unknown';

// Build YAML tags
const tagsYaml = data.tags.map(t => `  - ${t}`).join('\n');

// Escape double quotes in strings for YAML
const escapeYaml = (str) => str.replace(/"/g, '\\"');

// Build frontmatter
const frontmatter = [
  '---',
  `author: ${author}`,
  `pubDatetime: ${pubDatetime}`,
  `title: "${escapeYaml(data.title)}"`,
  `slug: "${slug}"`,
  `description: "${escapeYaml(data.description)}"`,
  `url: "${data.url}"`,
  'tags:',
  tagsYaml,
  `rating: ${data.rating}`,
  '---',
].join('\n');

const markdown = `${frontmatter}\n\n${data.summary}\n`;
const filePath = `src/content/ai-radar/${slug}.md`;
const commitMessage = `feat(ai-radar): add ${slug}`;

return [{
  json: {
    markdown,
    filePath,
    commitMessage,
    slug,
  }
}];
